protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // Preserve EF Core 8 discriminator property name so existing
        // documents (which store "Discriminator") remain readable and
        // direct SQL queries filtering on c.Discriminator keep working.
        entity.HasDiscriminator<string>("Discriminator");

        // Preserve EF Core 8 compound id format ("Product|123") so
        // existing 500K documents remain addressable by point-reads.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

